-- ACID transactions in InnoDB
START TRANSACTION;
  UPDATE accounts SET balance = balance - 100 WHERE id = 'A';
  UPDATE accounts SET balance = balance + 100 WHERE id = 'B';
  -- If anything fails: ROLLBACK;
COMMIT;

-- Isolation levels (from weakest to strongest):

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;  -- dirty reads possible; almost never useful
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;    -- no dirty reads; non-repeatable reads possible
SET TRANSACTION ISOLATION LEVEL REPEATABLE READ;   -- MySQL DEFAULT; snapshot at first read
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;      -- strictest; equivalent to executing serially

-- InnoDB's REPEATABLE READ uses MVCC (multi-version concurrency control) — same as PostgreSQL.
-- You SEE a consistent snapshot from your transaction's start; other transactions don't affect you.
-- Writes still take locks and can conflict (lost update if you're not careful).

-- SELECT ... FOR UPDATE — acquire a row-level lock to prevent concurrent modification
START TRANSACTION;
  SELECT balance INTO @bal FROM accounts WHERE id = 'A' FOR UPDATE;
  UPDATE accounts SET balance = @bal - 100 WHERE id = 'A';
COMMIT;
